import React from "react";
import Jumbotron from "./components/jumbotron/Jumbotron";
import Home from "./components/home/Home";
import { BrowserRouter as Router, Switch, Route } from "react-router-dom";

function App() {
  return (
    <>
      <Router>
        <Switch>
          <Route path="/home">
            <Home />
          </Route>
          <Route path="/">
            <Jumbotron />
          </Route>
        </Switch>
      </Router>
    </>
  );
}

export default App;
